scwin.f_Excel = async function() {

    if (ds_master.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    // gr_master.SetExcelTitle(0, "");
    // gr_master.SetExcelTitle(1, "value:OPUS 내역;"       // 표시할 타이틀
    //                         + "font-face:'돋움체';" // 폰트
    //                         + "font-size:18pt;"     // 폰트 크기
    //                         + "font-color:black;"   // 폰트 색깔
    //                         + "bgcolor:#ffffff;"    // 배경 색깔
    //                         + "align:center;"       // 정렬
    //                         + "line-color:white;"   // 타이틀 부분 테두리선 색깔
    //                         + "line-width:0pt;"     // 타이틀 테두리선 굵기
    //                         + "skiprow:1;");        // 타이틀 다음 떼는 로우 수

    // fileName = 'OPUS 전표발행 내역';
    // cfGridToExcel(gr_master,fileName,fileName,2+8+16);

    let sheetTitle = "OPUS 발행";
    let fileName   = "OPUS 전표발행 내역";

    let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
        let options = {
            fileName         : fileName+ ".xlsx",
            sheetName        : fileName,       // 2026-05-11 : 시트명 수정
            startRowIndex    : 2,  // 내용 앞으로 몇 row 띄우는지...
            startColumnIndex : 0,
            bodyWordwrap     : true,   // 줄바꿈
            useSubTotal      : true,   // 소계출력
            hiddenVisible    : true    // 히든 컬럼 출력
        };
        const infoArr = [{
                        rowIndex : 0, colIndex : 0, rowSpan : 1, colSpan : 21 /* 병합할 컬럼갯수 */, text : sheetTitle , textAlign : "center", drawBorder: false, fontSize: "18px", fontName: "돋움체"
                    },
                ];

        $c.data.downloadGridViewExcel(gr_master, options, infoArr);
    }
};


